 1	import * as React from 'react';
 2	import { Grid, GridItem } from '@patternfly/react-core';
 3	import { useTranslation } from 'react-i18next';
 4	import { Link } from 'react-router-dom-v5-compat';
 5	import { useTaskRuns } from '../hooks/useTaskRuns';
 6	import { useMultiClusterProxyService } from '../hooks/useMultiClusterProxyService';
 7	import { resourcePath } from '../utils/resource-link';
 8	import { PipelineRunModel } from '../../models';
 9	import { ComputedStatus, PipelineRunKind } from '../../types';
10	import { getPLRLogSnippet } from '../logs/pipelineRunLogSnippet';
11	import { pipelineRunStatus } from '../utils/pipeline-filter-reducer';
12	import Status from '../status/Status';
13	import LogSnippetBlock from '../logs/LogSnippetBlock';
14	import { fromNow } from '../pipelines-overview/dateTime';
15	import LogSnippet from '../logs/LogSnippet';
16	import './PipelineRunItem.scss';
17	
18	type PipelineRunItemProps = {
19	  pipelineRun: PipelineRunKind;
20	};
21	
22	const PipelineRunItem: React.FC<PipelineRunItemProps> = ({ pipelineRun }) => {
23	  const { t } = useTranslation('plugin__pipelines-console-plugin');
24	  const { isResourceManagedByKueue } = useMultiClusterProxyService({ managedBy: pipelineRun?.spec?.managedBy });
25	  const {
26	    metadata: { name, namespace, creationTimestamp },
27	    status,
28	  } = pipelineRun;
29	  const plrStatus = pipelineRunStatus(pipelineRun);
30	  const pipelineRunFinished =
31	    plrStatus !== ComputedStatus.Running &&
32	    plrStatus !== ComputedStatus.Pending &&
33	    plrStatus !== ComputedStatus.Cancelling;
34	  const [taskRuns] = useTaskRuns(
35	    pipelineRun?.metadata?.namespace,
36	    pipelineRun?.metadata?.name,
37	    { 
38	      pipelineRunFinished, 
39	      pipelineRunManagedBy: pipelineRun?.spec?.managedBy 
40	    },
41	  );
42	  const path = resourcePath(PipelineRunModel, name, namespace);
43	  const lastUpdated = status
44	    ? status.completionTime || status.startTime || creationTimestamp
45	    : creationTimestamp;
46	  const logDetails = getPLRLogSnippet(pipelineRun, taskRuns);
47	  return (
48	    <li className="opp-pipeline-run-item list-group-item">
49	      <Grid hasGutter>
50	        <GridItem span={6}>
51	          <div>
52	            <Link to={`${path}`}>{name}</Link>
53	            {lastUpdated && (
54	              <>
55	                {' '}
56	                <span className="opp-pipeline-run-item__time pf-v6-u-text-color-subtle">
57	                  ({fromNow(lastUpdated)})
58	                </span>
59	              </>
60	            )}
61	          </div>
62	        </GridItem>
63	        <GridItem span={3}>
64	          <Status status={pipelineRunStatus(pipelineRun) || 'Pending'} />
65	        </GridItem>
66	        <GridItem span={3} className="pf-v6-u-text-align-right">
67	          <Link to={`${path}/logs`}>{t('View logs')}</Link>
68	        </GridItem>
69	        {logDetails && (
70	          <GridItem>
71	            <LogSnippetBlock
72	              logDetails={logDetails}
73	              namespace={namespace}
74	              isResourceManagedByKueue={isResourceManagedByKueue}
75	              pipelineRunName={name}
76	            >
77	              {(logSnippet: string) => (
78	                <LogSnippet
79	                  message={logDetails.title}
80	                  logSnippet={logSnippet}
81	                />
82	              )}
83	            </LogSnippetBlock>
84	          </GridItem>
85	        )}
86	      </Grid>
87	    </li>
88	  );
89	};
90	
91	export default PipelineRunItem;

